requests.postData:
{"query":"
  query AccountCoinBalances($address: String) {
    current_coin_balances(where: { owner_address: { _eq: $address } }) {
      amount
      coin_info {
        coin_type
        creator_address
        decimals
        name
        symbol
      }
    }
  }
","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f"},"operationName":"AccountCoinBalances"}

{"query":"
  query getTokenPendingClaims($address: String!, $offset: Int, $limit: Int) {
    current_token_pending_claims(
      where: {
        _or: [
          { from_address: { _eq: $address }, amount: { _gt: "0" } }
          { to_address: { _eq: $address }, amount: { _gt: "0" } }
        ]
      }
      order_by: [
        { last_transaction_timestamp: desc }
        { last_transaction_version: desc }
      ]
      offset: $offset
      limit: $limit
    ) {
      ...CurrentTokenPendingClaims
    }
  }

  fragment CurrentTokenPendingClaims on current_token_pending_claims {
    amount
    from_address
    to_address
    last_transaction_version
    last_transaction_timestamp
    property_version
    current_token_data {
      ...TokenDataFields
    }
    current_collection_data {
      ...CollectionDataFields
    }
    token {
      ...TokensDataFields
    }
  }

  fragment TokenDataFields on current_token_datas {
    creator_address
    collection_name
    description
    metadata_uri
    name
    token_data_id_hash
    collection_data_id_hash
  }

  fragment CollectionDataFields on current_collection_datas {
    metadata_uri
    supply
    description
    collection_name
    collection_data_id_hash
    table_handle
    creator_address
  }

  fragment TokensDataFields on tokens {
    creator_address
    collection_name
    name
    token_data_id_hash
    collection_data_id_hash
    property_version
    token_properties
    transaction_timestamp
    transaction_version
  }
","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f","offset":0,"limit":10},"operationName":"getTokenPendingClaims"}

{"query":"
  query getCurrentFungibleAssetBalances(
    $address: String!
    $filtered_coins: [String!]
  ) {
    current_fungible_asset_balances(
      where: {
        owner_address: { _eq: $address }
        asset_type: { _nin: $filtered_coins }
      }
    ) {
      amount
      asset_type
      metadata {
        asset_type
        decimals
        icon_uri
        name
        symbol
      }
    }
  }
","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f","filtered_coins":[]},"operationName":"getCurrentFungibleAssetBalances"}

